+            report.tiers.raw_sha256_match
+        );
+        println!(
+            "  canonical_sha256_match: {:?}",
+            report.tiers.canonical_sha256_match
+        );
+        println!("  logical_match:          {:?}", report.tiers.logical_match);
+
+        if let Some(ref diag) = diagnostic {
